/**
 * 创建一个防抖函数，延迟调用目标函数
 * 
 * @param {Function} fn  要防抖的函数
 * @param {number}   ms  延迟毫秒数
 * @param {Object}   options
 * @param {boolean}  options.leading  是否在延迟开始前立即执行一次（默认 false）
 * @param {boolean}  options.trailing 是否在延迟结束后执行（默认 true）
 * @returns {Function} 防抖后的函数，附带 .cancel() 和 .flush() 方法
 */
function debounce(fn, ms, options = {}) {
  const { leading = false, trailing = true } = options

  let timer = null
  let lastArgs = null
  let lastThis = null
  let invoked = false  // 标记 leading 调用是否已发生

  function invoke() {
    if (!trailing) return
    fn.apply(lastThis, lastArgs)
    invoked = false
  }

  function debounced(...args) {
    lastArgs = args
    lastThis = this

    // leading 执行：第一次调用立即触发，之后只重置定时器
    if (leading && !timer) {
      fn.apply(this, args)
      invoked = true
    }

    // 清除上次定时器，重新计时
    clearTimeout(timer)
    timer = setTimeout(() => {
      timer = null
      // trailing 执行：只在 leading 未调用过时才执行
      // 若 leading 已执行，但后续还有调用，定时器到期时 still 需要执行
      if (trailing && !(leading && invoked)) {
        invoke()
      }
      invoked = false
    }, ms)
  }

  // 立即取消待执行的调用
  debounced.cancel = () => {
    clearTimeout(timer)
    timer = null
    invoked = false
  }

  // 立即执行待处理的调用
  debounced.flush = () => {
    clearTimeout(timer)
    timer = null
    if (lastArgs) {
      fn.apply(lastThis, lastArgs)
      invoked = true
    }
  }

  return debounced
}
```

---

**一点原理说明：**

debounce 的核心思路是用一个定时器把多次密集调用"压扁"成一次。好比电梯门——有人进来就重置关门计时，等人走完了才真正关上。

- **leading**：先开门再等（适用于"复制粘贴"等需要即时反馈的场景）
- **trailing**：等消停了再执行（适用于搜索输入、窗口 resize）
- **二者同时为 true**：只有第一次立即执行，后续连续调用只重置定时器，不会在结束后再补一次（避免了重复）

附带 `.cancel()` 和 `.flush()` 两个方法，方便组件卸载时清理，或需要在超时前主动触发的场景。

